        "question": "What is a decorator in Python?",
        "options": [
          "A function that modifies another function",
          "A built-in data type",
          "A module for handling exceptions",
          "A type of loop"
        ],
        "correctAnswer": 0,
        "explanation": "A decorator is a function that modifies the behavior of another function."
      },
      {
        "question": "Which of the following is used to create a generator in Python?",
        "options": [
          "def keyword",
          "yield keyword",
          "return keyword",
          "async keyword"
        ],
        "correctAnswer": 1,
        "explanation": "The 'yield' keyword is used to create a generator in Python."
      },
      {
        "question": "What does the 'with' statement do in Python?",
        "options": [
          "Handles exceptions",
          "Manages resources",
          "Defines a function",
          "Imports modules"
        ],
        "correctAnswer": 1,
        "explanation": "The 'with' statement is used to manage resources, ensuring proper acquisition and release."
      },
      {
        "question": "What is the purpose of the 'self' parameter in class methods?",
        "options": [
          "To refer to the class itself",
          "To refer to the instance of the class",
          "To define class variables",
          "To call other methods"
        ],
        "correctAnswer": 1,
        "explanation": "'self' refers to the instance of the class, allowing access to instance variables and methods."
      }
    ]
  }
